// reviewFailureRunner is a test-local deterministic Executor + Reviewer pair
// driving the "N reviewer failures, then 1 success" scenario. Test-local on
// purpose: a shared cross-package testfixtures package would be unreachable
// from main() under deadcode RTA (production-reachability check).
type reviewFailureRunner struct {
	resultRev     string
	failUntilCall int
	reviewCalls   atomic.Int32
	execCalls     atomic.Int32
}

func (r *reviewFailureRunner) Executor() agent.ExecuteBeadExecutor {
	return agent.ExecuteBeadExecutorFunc(func(_ context.Context, beadID string) (agent.ExecuteBeadReport, error) {
		n := r.execCalls.Add(1)
		return agent.ExecuteBeadReport{
			BeadID:    beadID,
			Status:    agent.ExecuteBeadStatusSuccess,
			SessionID: fmt.Sprintf("rfr-sess-%d", n),
			ResultRev: r.resultRev,
		}, nil
	})
}

func (r *reviewFailureRunner) Reviewer() agent.BeadReviewer {
	return reviewerFn(func(_ context.Context, _, resultRev string, _ agent.ImplementerRouting) (*agent.ReviewResult, error) {
		n := int(r.reviewCalls.Add(1))
		if n <= r.failUntilCall {
			class := evidence.OutcomeReviewProviderEmpty
			return &agent.ReviewResult{
					Verdict:   agent.VerdictBlock,
					Error:     class,
					ResultRev: resultRev,
				}, fmt.Errorf("review-failure-runner: %s: %w", class,
					errors.New("simulated reviewer failure"))
		}
		return &agent.ReviewResult{
			Verdict:   agent.VerdictApprove,
			Rationale: "review-failure-runner: APPROVE",
			ResultRev: resultRev,
		}, nil
	})
}

func (r *reviewFailureRunner) ReviewCalls() int { return int(r.reviewCalls.Load()) }
func (r *reviewFailureRunner) ExecCalls() int   { return int(r.execCalls.Load()) }

type reviewerFn func(ctx context.Context, beadID, resultRev string, impl agent.ImplementerRouting) (*agent.ReviewResult, error)

func (f reviewerFn) ReviewBead(ctx context.Context, beadID, resultRev string, impl agent.ImplementerRouting) (*agent.ReviewResult, error) {
	return f(ctx, beadID, resultRev, impl)
}

// TestReviewRetryThresholdFromConfigServer is the SD-024 Stage 1 behavioral
// proof that the server dispatch path at runWorker carries
// review_max_retries from .ddx/config.yaml through to the running loop.
//
// The test mirrors the production wiring introduced in workers.go: it
// drives StartExecuteLoop → runWorker against a real on-disk
// .ddx/config.yaml (the same file the runWorker dispatch site's
// config.LoadAndResolve call reads). The deterministic review-failure
// fixture (test-local) provides the executor + reviewer pair via
// BeadWorkerFactory so behavior is observable end-to-end without a real
// agent harness.
//
// Configured values:
//   - .ddx/config.yaml: review_max_retries: 5
//   - fixture: FailUntilCall=4 (attempts 1-4 return reviewer error,
//     attempt 5 returns APPROVE)
//
// Expected behavior:
//   - 5 StartExecuteLoop iterations drive 5 reviewer attempts.
//   - attempts 1-4 emit review-error events.
//   - attempt 5 emits an APPROVE review event and the loop closes
//     the bead via CloseWithEvidence.
//   - no review-manual-required event fires (threshold=5 ≥ attempts=5).
func TestReviewRetryThresholdFromConfigServer(t *testing.T) {
	const (
		failUntil = 4
		threshold = 5
		beadID    = "ddx-server-rmr-001"
		fixedRev  = "cafebabe00112233"
	)

	projectRoot := t.TempDir()
	ddxDir := filepath.Join(projectRoot, ".ddx")
	require.NoError(t, os.MkdirAll(ddxDir, 0o755))

	// Real on-disk .ddx/config.yaml — this is the file the server
	// dispatch path's config.LoadAndResolve call reads. The presence of
	// review_max_retries: 5 here is the entire premise of the test.
	cfgYAML := `version: "1.0"
library:
  path: ./library
  repository:
    url: https://github.com/example/repo
    branch: main
review_max_retries: 5
`
	require.NoError(t, os.WriteFile(filepath.Join(ddxDir, "config.yaml"), []byte(cfgYAML), 0o644))

	store := bead.NewStore(ddxDir)
	require.NoError(t, store.Init())
	require.NoError(t, store.Create(&bead.Bead{ID: beadID, Title: "server e2e review-retry threshold", Priority: 0}))

	runner := &reviewFailureRunner{
		resultRev:     fixedRev,
		failUntilCall: failUntil,
	}

	m := NewWorkerManager(projectRoot)
	defer m.StopWatchdog()
	// Inject the deterministic executor+reviewer pair through the same
	// factory seam runWorker honours in production. The factory bypasses
	// the real agent runner so behavior is fully observable.
	m.BeadWorkerFactory = func(s agent.ExecuteBeadLoopStore) *agent.ExecuteBeadWorker {
		return &agent.ExecuteBeadWorker{
			Store:    s,
			Executor: runner.Executor(),
			Reviewer: runner.Reviewer(),
		}
	}

	// Drive failUntil + 1 iterations through StartExecuteLoop → runWorker
	// (one --once invocation per attempt, matching the production loop's
	// per-iteration claim/release rhythm). Between iterations the test
	// unclaims the bead because the loop intentionally leaves it claimed
	// on a reviewer-error iteration.
	const totalIterations = failUntil + 1
	for i := 0; i < totalIterations; i++ {
		rec, err := m.StartExecuteLoop(ExecuteLoopWorkerSpec{
			ProjectRoot: projectRoot,
			Once:        true,
		})
		require.NoErrorf(t, err, "iteration %d: StartExecuteLoop", i+1)
		_ = waitForWorkerExit(t, m, rec.ID, 10*time.Second)
		if i < totalIterations-1 {
			require.NoErrorf(t, store.Unclaim(beadID), "iteration %d: unclaim", i+1)
		}
	}

	assert.Equal(t, totalIterations, runner.ReviewCalls(),
		"reviewer must be invoked once per driven iteration")
	assert.Equal(t, totalIterations, runner.ExecCalls(),
		"executor must be invoked once per driven iteration")

	events, err := store.Events(beadID)
	require.NoError(t, err)

	var (
		reviewErrorCount    int
		reviewApproveCount  int
		manualRequiredCount int
	)
	for _, ev := range events {
		switch ev.Kind {
		case "review-error":
			reviewErrorCount++
		case "review":
			if ev.Summary == "APPROVE" {
				reviewApproveCount++
			}
		case "review-manual-required":
			manualRequiredCount++
		}
	}

	assert.Equal(t, failUntil, reviewErrorCount,
		"reviewer-error count must match the fixture's FailUntilCall")
	assert.Equal(t, 1, reviewApproveCount,
		"the (FailUntilCall+1)th iteration must record an APPROVE review event")
	assert.Equal(t, 0, manualRequiredCount,
		"with review_max_retries=%d ≥ attempts=%d the loop must NOT emit review-manual-required",
		threshold, totalIterations)

	got, err := store.Get(beadID)
	require.NoError(t, err)
	assert.Equal(t, "closed", got.Status,
		"after APPROVE on attempt %d the loop must close the bead", totalIterations)

	// Defensive: a stale heartbeat ticker in the loop could outlive the
	// final iteration. Give it a beat to settle so test cleanup is clean.
	time.Sleep(10 * time.Millisecond)
}

	return record, nil
}

func (m *WorkerManager) runPluginAction(ctx context.Context, id, dir string, spec PluginActionWorkerSpec, handle *workerHandle, log io.Writer, progressCh chan agent.ProgressEvent, run PluginActionExecutor) {
	startedAt := time.Now().UTC()
	phaseSeq := 1
	sendProgress(progressCh, agent.ProgressEvent{
		EventID:   "evt-" + randomSuffix(8),
		AttemptID: id,
		WorkerID:  id,
		ProjectID: spec.ProjectRoot,
		Phase:     "running",
		PhaseSeq:  phaseSeq,
		TS:        startedAt,
		Message:   fmt.Sprintf("%s plugin %s", spec.Action, spec.Name),
	})
	if log != nil {
		_, _ = fmt.Fprintf(log, "%s plugin %s (%s)\n", spec.Action, spec.Name, spec.Scope)
	}

	state, err := run(ctx)
	if ctxErr := ctx.Err(); ctxErr != nil && err == nil {
		err = ctxErr
	}

	phase := "done"
	message := state
	if err != nil {
		phase = "failed"
		message = err.Error()
	}
	phaseSeq++
	sendProgress(progressCh, agent.ProgressEvent{
		EventID:   "evt-" + randomSuffix(8),
		AttemptID: id,
		WorkerID:  id,
		ProjectID: spec.ProjectRoot,
		Phase:     phase,
		PhaseSeq:  phaseSeq,
		TS:        time.Now().UTC(),
		ElapsedMS: time.Since(startedAt).Milliseconds(),
		Message:   message,
	})

	if log != nil {
		if err != nil {
			_, _ = fmt.Fprintf(log, "failed: %s\n", err)
		} else {
			_, _ = fmt.Fprintf(log, "completed: %s\n", state)
		}
	}

	close(progressCh)
	<-handle.progressDone

	m.mu.Lock()
	record := handle.record
	preservedState := ""
	if record.State == "stopped" || record.State == "reaped" {
		preservedState = record.State
	}
	record.FinishedAt = time.Now().UTC()
	_ = handle.logFile.Close()
	if err != nil {
		record.State = "failed"
		record.Status = "failed"
		record.Error = err.Error()
		record.LastError = err.Error()
	} else {
		record.State = "exited"
		record.Status = "success"
		record.LastResult = &WorkerExecutionResult{
			AttemptID: id,
			WorkerID:  id,
			Status:    state,
			Detail:    fmt.Sprintf("%s plugin %s", spec.Action, spec.Name),
		}
	}
	if preservedState != "" {
		record.State = preservedState
		record.Status = preservedState
	}
	_ = m.writeRecord(dir, record)
	handle.record = record
	m.mu.Unlock()
}

// buildRoutePreflight constructs the route preflight gate (FEAT-006 D3, ddx-98e6e9ef).
// Before claiming a bead, the loop consults upstream ResolveRoute against the
// resolved (harness, model). If the upstream surfaces agent.ErrHarnessModelIncompatible
// (or any other typed error), the loop exits with a worker-level execution_failed
// record — no bead is claimed, no executor invocation, no tier-attempt event burn.
// DDx does NOT duplicate the upstream allow-list; this gate only consumes the typed
// incompatibility surface.
//
// Returns nil (no preflight) when:
//   - hasBeadWorkerFactory is true (test injection path), OR
//   - spec.OpaquePassthrough is true (ddx work path — routing belongs to the agent
//     service), OR
//   - the operator pinned NOTHING (no Profile, no Model). In the auto-route case
//     the strict ResolveRoute path is too aggressive — it picks a default catalog
//     model from the harness's first entry and rejects exact-pin-only candidates.
//     Per ddx-9e4c238d / ddx-1e516bc9: bare auto-route must pass through to fizeau's
//     more lenient Execute path on each attempt.
func buildRoutePreflight(projectRoot string, spec ExecuteLoopWorkerSpec, hasBeadWorkerFactory bool) func(ctx context.Context, harness, model string) error {
	if hasBeadWorkerFactory || spec.OpaquePassthrough {
		return nil
	}
	// Auto-route case: operator pinned no Profile and no Model. Skip strict
	// preflight; let fizeau's Execute handle routing on each attempt.
	if spec.Profile == "" && spec.Model == "" {
		return nil
	}
	preflightSvc, preflightErr := agent.NewServiceFromWorkDir(projectRoot)
	return func(ctx context.Context, harness, model string) error {
		svc := preflightSvc
		if svc == nil {
			return preflightErr
		}
		req := agentlib.RouteRequest{
			Profile: agent.NormalizeRoutingProfile(spec.Profile),
		}
		if harness != "" {
			req.Harness = harness
		}
		if model != "" {
			req.Model = model
		}
		_, rErr := svc.ResolveRoute(ctx, req)
		return rErr
	}
}

